import { LlmRequest, LlmResponse, Session } from '@google/adk';
import { Blob, CodeExecutionResult, Content, ExecutableCode, FileData, FinishReason, FunctionCall, FunctionResponse, GenerateContentResponseUsageMetadata, GroundingMetadata, PartMediaResolution, VideoMetadata } from '@google/genai';
export interface UserMessage {
    text?: string;
    content?: Content;
    stateDelta?: Record<string, unknown>;
}
export interface TestSpec {
    description: string;
    agent: string;
    initialState?: Record<string, unknown>;
    userMessages?: UserMessage[];
}
export interface LlmRecording {
    llmRequest?: LlmRequest;
    llmResponse?: LlmResponse;
}
export interface ToolRecording {
    toolCall?: FunctionCall;
    toolResponse?: FunctionResponse;
}
export interface Recording {
    userMessageIndex: number;
    agentName: string;
    llmRecording?: LlmRecording;
    toolRecording?: ToolRecording;
}
export interface Recordings {
    recordings: Recording[];
}
export interface TestInfo {
    name: string;
    spec: TestSpec;
    session: Session;
    recordings: Recordings;
}
export interface FilteredEventActions {
    skipSummarization?: boolean;
    stateDelta?: {
        [key: string]: unknown;
    };
    artifactDelta: {
        [key: string]: number;
    };
    transferToAgent?: string;
    escalate?: boolean;
}
export interface FilteredPart {
    mediaResolution?: PartMediaResolution;
    codeExecutionResult?: CodeExecutionResult;
    executableCode?: ExecutableCode;
    fileData?: FileData;
    inlineData?: Blob;
    text?: string;
    thought?: boolean;
    videoMetadata?: VideoMetadata;
}
export interface FilteredContent {
    parts?: FilteredPart[];
    role?: string;
}
export interface FilteredEvent {
    author?: string;
    branch?: string;
    actions: FilteredEventActions;
    content?: FilteredContent;
    groundingMetadata?: GroundingMetadata;
    partial?: boolean;
    turnComplete?: boolean;
    errorCode?: string;
    errorMessage?: string;
    interrupted?: boolean;
    customMetadata?: {
        [key: string]: unknown;
    };
    usageMetadata?: GenerateContentResponseUsageMetadata;
    finishReason?: FinishReason;
}
